59: // Implement APB I/O map to AES interface
60: // Write side
61: always @(posedge clk_i)
62:     begin
63:         if(~rst_ni)
64:             begin
65:                 start <= 0;
66:                 p_c[0] <= 0;
67:                 p_c[1] <= 0;
68:                 p_c[2] <= 0;
69:                 p_c[3] <= 0;
70:                 state[0] <= 0;
71:                 state[1] <= 0;
72:                 state[2] <= 0;
73:                 state[3] <= 0;
74:             end
75:         else if(external_bus_io.write)
76:             case(external_bus_io.addr[6:2])
77:                 0:
78:                     start <= external_bus_io.wdata[0];
79:                 1:
80:                     p_c[3] <= external_bus_io.wdata;
81:                 2:
82:                     p_c[2] <= external_bus_io.wdata;
83:                 3:
84:                     p_c[1] <= external_bus_io.wdata;
85:                 4:
86:                     p_c[0] <= external_bus_io.wdata;
87: 		// no write access to ct registers !!
88: 
89:                 16:
90:                     state[3] <= external_bus_io.wdata;
91:                 17:
92:                     state[2] <= external_bus_io.wdata;
93:                 18:
94:                     state[1] <= external_bus_io.wdata;
95:                 19:
96:                     state[0] <= external_bus_io.wdata;
97:                 default:
98:                     ;
99:             endcase
100:     end // always @ (posedge wb_clk_i)
101: 
102: // Implement MD5 I/O memory map interface
103: // Read side
104: //always @(~external_bus_io.write)
105: always @(*)
106:     begin
107:         case(external_bus_io.addr[6:2])
108:             0:
109:                 external_bus_io.rdata = {31'b0, start};
110:             1:
111:                 external_bus_io.rdata = p_c[3];
112:             2:
113:                 external_bus_io.rdata = p_c[2];
114:             3:
115:                 external_bus_io.rdata = p_c[1];
116:             4:
117:                 external_bus_io.rdata = p_c[0];
118:             11:
119:                 external_bus_io.rdata = {31'b0, ct_valid};
120:             12:
121:                 external_bus_io.rdata = ct[127:96];
122:             13:
123:                 external_bus_io.rdata = ct[95:64];
124:             14:
125:                 external_bus_io.rdata = ct[63:32];
126:             15:
127:                 external_bus_io.rdata = ct[31:0];
128:             16:
129:                 external_bus_io.rdata = key_big[191:160];
130:             17:
131:                 external_bus_io.rdata = key_big[159:128];
132:             18:
133:                 external_bus_io.rdata = key_big[127:96];
134:             19:
135:                 external_bus_io.rdata = key_big[95:64];
136:             20:
137:                 external_bus_io.rdata = key_big[63:32];
138:             21:
139:                 external_bus_io.rdata = key_big[31:0];
140:             22:
141:                 external_bus_io.rdata = inter_state[127:96];
142:             23:
143:                 external_bus_io.rdata = inter_state[95:64];
144:             24:
145:                 external_bus_io.rdata = inter_state[63:32];
146:             25:
147:                 external_bus_io.rdata = inter_state[31:0];
148:             default:
149:                 external_bus_io.rdata = 32'b0;
150:         endcase
151:     end // always @ (*)
